import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import toast from 'react-hot-toast';
import { LayoutDashboard, Calendar, Activity, LogOut, Plus, User, Clock, MapPin, Trash2, ChevronRight, Heart, Bell } from 'lucide-react';

const API = "http://localhost:5000/api";

const statusColor = {
  pending: 'status-pending',
  assigned: 'status-assigned',
  active: 'status-active',
  completed: 'status-completed',
  cancelled: 'status-cancelled'
};

const careIcon = { elderly: '👴', maternity: '🤱', childcare: '👶' };

export default function UserDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('overview');
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchBookings(); }, []);

  // ✅ FIXED API + TOKEN
  const fetchBookings = async () => {
    const token = localStorage.getItem("token");

    try {
      const { data } = await axios.get(`${API}/bookings/my-bookings`, {
        headers: {
          Authorization: `Bearer ${token}`
        }
      });

      setBookings(data);

    } catch (err) {
      console.log(err);
      toast.error('Failed to load bookings');
    } finally {
      setLoading(false);
    }
  };

  // ✅ FIXED cancel logic
  const cancelBooking = async (id) => {
    if (!window.confirm('Cancel this booking?')) return;

    const token = localStorage.getItem("token");

    try {
      await axios.patch(
        `${API}/bookings/${id}/status`,
        { status: 'cancelled' },
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      toast.success('Booking cancelled');
      fetchBookings();

    } catch (err) {
      console.log(err);
      toast.error('Failed to cancel');
    }
  };

  const active = bookings.filter(b => ['active', 'assigned'].includes(b.status));
  const pending = bookings.filter(b => b.status === 'pending');
  const completed = bookings.filter(b => b.status === 'completed');

  return (
    <div className="dashboard-layout">

      {/* SIDEBAR */}
      <aside className="sidebar">
        <div className="sidebar-logo">
          <Heart size={18}/> Prana Solutions
        </div>

        <nav className="sidebar-nav">
          <div className="sidebar-item" onClick={() => setActiveTab('overview')}>
            <LayoutDashboard size={18}/> Overview
          </div>
          <div className="sidebar-item" onClick={() => setActiveTab('bookings')}>
            <Calendar size={18}/> My Bookings
          </div>
        </nav>

        <div style={{ marginTop: 'auto' }}>
          <div className="sidebar-item" onClick={() => { logout(); navigate('/'); }}>
            <LogOut size={18}/> Logout
          </div>
        </div>
      </aside>

      {/* MAIN */}
      <main className="main-content">

        {/* OVERVIEW */}
        {activeTab === 'overview' && (
          <>
            <h1>Welcome {user?.name}</h1>

            <div className="stats-grid">
              <div className="card">Total: {bookings.length}</div>
              <div className="card">Active: {active.length}</div>
              <div className="card">Pending: {pending.length}</div>
              <div className="card">Completed: {completed.length}</div>
            </div>
          </>
        )}

        {/* BOOKINGS */}
        {activeTab === 'bookings' && (
          <>
            <h2>My Bookings</h2>

            {loading ? (
              <p>Loading...</p>
            ) : bookings.length === 0 ? (
              <p>No bookings yet</p>
            ) : (
              bookings.map(b => (
                <div key={b._id} className="card" style={{ marginBottom: 10 }}>
                  <p><b>{b.patient?.name}</b></p>
                  <p>{b.careType}</p>
                  <p>Status: {b.status}</p>

                  {['pending', 'assigned'].includes(b.status) && (
                    <button onClick={() => cancelBooking(b._id)}>
                      Cancel
                    </button>
                  )}
                </div>
              ))
            )}
          </>
        )}

      </main>
    </div>
  );
}
